function getBreakdown(txs: Transaction[]): Breakdown {
  const result: Breakdown = {
    Food: 0, Housing: 0, Transport: 0,
    Entertainment: 0, Health: 0, Other: 0,
  };

  for (const t of txs) {
    if (t.type === 'EXPENSE') {
      result[t.category] += t.amount;
    }
  }

  return result;
}

